export function createInputSignal<T, TransformT>(
  initialValue: T,
  options?: InputOptions<T, TransformT>,
): InputSignalWithTransform<T, TransformT> {
  const node: InputSignalNode<T, TransformT> = Object.create(INPUT_SIGNAL_NODE);

  node.value = initialValue;

  // Perf note: Always set `transformFn` here to ensure that `node` always
  // has the same v8 class shape, allowing monomorphic reads on input signals.
  node.transformFn = options?.transform;

  function inputValueFn() {
    // Record that someone looked at this signal.
    producerAccessed(node);

    if (node.value === REQUIRED_UNSET_VALUE) {
      let message: string | null = null;
      if (ngDevMode) {
        const name = options?.debugName ?? options?.alias;
        message = `Input${name ? ` "${name}"` : ''} is required but no value is available yet.`;
      }
      throw new RuntimeError(RuntimeErrorCode.REQUIRED_INPUT_NO_VALUE, message);
    }

    return node.value;
  }

  (inputValueFn as any)[SIGNAL] = node;

  if (ngDevMode) {
    inputValueFn.toString = () => `[Input Signal: ${inputValueFn()}]`;
    node.debugName = options?.debugName;
  }

  return inputValueFn as InputSignalWithTransform<T, TransformT>;
}

@Injectable()
export class ScreenTrackingService implements OnDestroy {

  private disposable: Subscription | undefined;

  constructor(
    @Optional() router: Router,
    @Optional() title: Title,
    componentFactoryResolver: ComponentFactoryResolver,
    zone: NgZone,
    @Optional() userTrackingService: UserTrackingService,
    injector: Injector,
  ) {
    registerVersion('angularfire', VERSION.full, 'screen-tracking');
    // The APP_INITIALIZER that is making isSupported() sync for the sake of convenient DI
    // may not be done when services are initialized. Guard the functionality by first ensuring
    // that the (global) promise has resolved, then get Analytics from the injector.
    isSupported().then(() => {
      const analytics = injector.get(Analytics);
      if (!router || !analytics) { return; }
      zone.runOutsideAngular(() => {
        this.disposable = ɵscreenViewEvent(router, title, componentFactoryResolver).pipe(
          switchMap(async params => {
            if (userTrackingService) { await userTrackingService.initialized; }
            return logEvent(analytics, SCREEN_VIEW_EVENT, params);
          })
        ).subscribe();
      });
    });
  }

  ngOnDestroy() {
    if (this.disposable) {
      this.disposable.unsubscribe();
    }
  }

}

private setupPageNavigationDimming() {
  if (this.isServer) {
    return;
  }
  this.router.events
    .pipe(
      filter((e) => e instanceof NavigationStart),
      map(() => {
        // Only apply set the property if the navigation is not "immediate"
        return setTimeout(() => {
          this.progressBar().start();
        }, PROGRESS_BAR_DELAY);
      }),
      switchMap((timeoutId) => {
        return this.router.events.pipe(
          filter((e) => {
            return (
              e instanceof NavigationEnd ||
              e instanceof NavigationCancel ||
              e instanceof NavigationSkipped ||
              e instanceof NavigationError
            );
          }),
          take(1),
          map(() => timeoutId),
        );
      }),
    )
    .subscribe((timeoutId) => {
      // When the navigation finishes, prevent the navigating class from being applied in the timeout.
      clearTimeout(timeoutId);
      this.progressBar().complete();
    });
}

